import{_ as s,o as t,c as n,ae as e}from"./chunks/framework.Czhw_PXq.js";const g=JSON.parse('{"title":"Workspace 架构","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/19_Agent管理专题/05-workspace.md","filePath":"chapters/19_Agent管理专题/05-workspace.md"}'),p={name:"chapters/19_Agent管理专题/05-workspace.md"};function o(r,a,l,d,c,i){return t(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="workspace-架构" tabindex="-1">Workspace 架构 <a class="header-anchor" href="#workspace-架构" aria-label="Permalink to &quot;Workspace 架构&quot;">​</a></h1><blockquote><p>日期：2026-03-25 来源：内容运营助手群</p></blockquote><hr><p>user: 还有一个问题,关于群会话的workspace和agent的workspace的区别</p><p>assistant: ## 群会话 Workspace vs Agent Workspace 区别</p><h3 id="📁-两种-workspace" tabindex="-1">📁 两种 Workspace <a class="header-anchor" href="#📁-两种-workspace" aria-label="Permalink to &quot;📁 两种 Workspace&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>路径</th><th>说明</th></tr></thead><tbody><tr><td><strong>Agent Workspace</strong></td><td><code>~/.openclaw/workspaces/&lt;agent_id&gt;/</code></td><td>Agent 的&quot;大脑&quot;，存放 SOUL.md、AGENTS.md 等定义文件</td></tr><tr><td><strong>Agent State</strong></td><td><code>~/.openclaw/agents/&lt;agent_id&gt;/</code></td><td>Agent 的状态，存放 sessions、memory 等运行时数据</td></tr></tbody></table><h3 id="🎯-具体例子" tabindex="-1">🎯 具体例子 <a class="header-anchor" href="#🎯-具体例子" aria-label="Permalink to &quot;🎯 具体例子&quot;">​</a></h3><p>以 <strong>内容运营群 (-5111532435)</strong> 为例：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>📂 ~/.openclaw/workspaces/mo-youtube/     ← Agent 工作空间</span></span>
<span class="line"><span>├── SOUL.md      ← Agent 角色定义</span></span>
<span class="line"><span>├── AGENTS.md    ← Agent 指令</span></span>
<span class="line"><span>└── TOOLS.md     ← 工具说明</span></span>
<span class="line"><span></span></span>
<span class="line"><span>📂 ~/.openclaw/agents/mo-youtube/        ← Agent 状态</span></span>
<span class="line"><span>├── sessions/   ← 对话历史</span></span>
<span class="line"><span>└── memory/     ← 记忆数据</span></span></code></pre></div><h3 id="🔄-群会话与-agent-的关系" tabindex="-1">🔄 群会话与 Agent 的关系 <a class="header-anchor" href="#🔄-群会话与-agent-的关系" aria-label="Permalink to &quot;🔄 群会话与 Agent 的关系&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>群 (-5111532435)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── Binding 绑定</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>Agent (mo-yunying / mo-youtube)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── workspace: ~/.openclaw/workspaces/mo-youtube/  ← 定义</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └── agentDir: ~/.openclaw/agents/mo-youtube/     ← 状态</span></span></code></pre></div><h3 id="💡-关键区别" tabindex="-1">💡 关键区别 <a class="header-anchor" href="#💡-关键区别" aria-label="Permalink to &quot;💡 关键区别&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方面</th><th>Agent Workspace</th><th>群会话</th></tr></thead><tbody><tr><td><strong>作用</strong></td><td>定义 Agent 是谁、做什么</td><td>当前对话的上下文</td></tr><tr><td><strong>持久性</strong></td><td>静态配置</td><td>动态生成</td></tr><tr><td><strong>文件</strong></td><td>SOUL.md, AGENTS.md</td><td>sessions/*.jsonl</td></tr><tr><td><strong>修改频率</strong></td><td>偶尔修改</td><td>每次对话都变</td></tr></tbody></table><hr><h3 id="📌-总结" tabindex="-1">📌 总结 <a class="header-anchor" href="#📌-总结" aria-label="Permalink to &quot;📌 总结&quot;">​</a></h3><ul><li><strong>Workspace</strong> = Agent 的&quot;身份&quot;，定义它是什么角色</li><li><strong>群会话</strong> = 每次对话的&quot;临时状态&quot;，记录说过什么</li><li>群绑定 Agent → Agent 使用自己的 Workspace → 生成会话历史</li></ul><p>这样清楚了吗？</p>`,18)])])}const u=s(p,[["render",o]]);export{g as __pageData,u as default};
